import{_ as t,o,c as a,a4 as n}from"./chunks/framework.Cqne-ChA.js";const h=JSON.parse('{"title":"Getting Started with z/OS Open Source","description":"","frontmatter":{},"headers":[],"relativePath":"Guides/Pre-req.md","filePath":"Guides/Pre-req.md","lastUpdated":1776677767000}'),r={name:"Guides/Pre-req.md"};function s(i,e,p,l,u,c){return o(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="getting-started-with-z-os-open-source" tabindex="-1">Getting Started with z/OS Open Source <a class="header-anchor" href="#getting-started-with-z-os-open-source" aria-label="Permalink to &quot;Getting Started with z/OS Open Source&quot;">​</a></h1><p>Before you begin, make sure you have access to a z/OS UNIX environment and that your environment is correctly configured.</p><h2 id="setting-up-your-z-os-environment" tabindex="-1">Setting up your z/OS environment <a class="header-anchor" href="#setting-up-your-z-os-environment" aria-label="Permalink to &quot;Setting up your z/OS environment&quot;">​</a></h2><p>z/OS Open Source tools require <a href="https://www.ibm.com/docs/en/zos/3.1.0?topic=pages-enhanced-ascii" target="_blank" rel="noreferrer">z/OS Enhanced ASCII support</a>. This support enables automatic conversion between codepages for tagged files. To take advantage of this support, you need to set the following environment variables:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>export _BPXK_AUTOCVT=ON</span></span>
<span class="line"><span>export _CEE_RUNOPTS=&quot;$_CEE_RUNOPTS FILETAG(AUTOCVT,AUTOTAG) POSIX(ON)&quot;</span></span>
<span class="line"><span>export _TAG_REDIR_ERR=txt</span></span>
<span class="line"><span>export _TAG_REDIR_IN=txt</span></span>
<span class="line"><span>export _TAG_REDIR_OUT=txt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>We recommend adding these environment variables to your <code>.profile</code> or <code>.bashrc</code> startup script.</p><h2 id="required-tools" tabindex="-1">Required Tools <a class="header-anchor" href="#required-tools" aria-label="Permalink to &quot;Required Tools&quot;">​</a></h2><p>To consume zopen community, all you need is a z/OS UNIX system and unrestricted access to github.com.</p><h3 id="if-you-want-to-contribute-and-improve-the-z-os-open-source-tools" tabindex="-1">If you want to contribute and improve the z/OS Open Source Tools <a class="header-anchor" href="#if-you-want-to-contribute-and-improve-the-z-os-open-source-tools" aria-label="Permalink to &quot;If you want to contribute and improve the z/OS Open Source Tools&quot;">​</a></h3><p>You will need the IBM C/C++ compiler on your system. There are two options:</p><ul><li>Clang <ul><li>The default compiler is clang. You can download the pax edition from IBM at <a href="https://epwt-www.mybluemix.net/software/support/trial/cst/programwebsite.wss?siteId=1803" target="_blank" rel="noreferrer">https://epwt-www.mybluemix.net/software/support/trial/cst/programwebsite.wss?siteId=1803</a>. This version may be used for development of open source software. Alternatively, if you have IBM Open XL C/C++ installed, you can use it instead of clang.</li></ul></li><li>XL Clang <ul><li>You can download it as a web deliverable add-on feature to your XL C/C++ compiler <a href="https://www.ibm.com/servers/resourcelink/svc00100.nsf/pages/xlCC++V241ForZOsV24" target="_blank" rel="noreferrer">here</a>.</li></ul></li></ul><p>If you are building Go projects, you will need the IBM Open Enterprise SDK for Go compiler installed. You can obtain it here: <a href="https://www.ibm.com/products/open-enterprise-sdk-go-zos" target="_blank" rel="noreferrer">https://www.ibm.com/products/open-enterprise-sdk-go-zos</a></p><p>For more details on porting, visit the <a href="./Porting">porting to z/OS guide</a>.</p>`,13)])])}const m=t(r,[["render",s]]);export{h as __pageData,m as default};
